set default=0

# Menu de sélection
menuentry --class os --url = ${URL} --title "${DISTRO_NAME}" {
    linux16 /vmlinuz ${kernel_opts}
}

# Fonction de chargement des operating systems
function load_os() {
  case $1 in
      os1)
          # Chargement du premier operating system
          ;;
      *)
          echo "Error : le système ne prend pas en charge la commande $1" >&2
          exit 1
          ;;
  esac
}

# Fonction de chargement de l'operating system par défaut
function default_os() {
  load_os os1
}

# Définition des options et variables d'environnement
set option 'search'='os'
set option 'timeout' = 2
